#ifndef INDEX_WEBUI_H
#define INDEX_WEBUI_H
const char* index_webui = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Couch Potato Remotes</title>\n\n<style>\n:root {\n--bg: #f4f6f9;\n--card-bg: #ffffff;\n--primary: #2563eb;\n--primary-hover: #1e4ed8;\n--text: #1f2937;\n--border: #e5e7eb;\n}\n\n* {\nbox-sizing: border-box;\n}\n\nbody {\nmargin: 0;\nfont-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, sans-serif;\nbackground: var(--bg);\ncolor: var(--text);\ndisplay: flex;\njustify-content: center;\n}\n\n.container {\nwidth: 100%;\nmax-width: 900px;\npadding: 20px;\n}\n\nh1 {\nmargin-top: 0;\ntext-align: center;\n}\n\n.card {\nbackground: var(--card-bg);\npadding: 20px;\nborder-radius: 14px;\nbox-shadow: 0 4px 10px rgba(0,0,0,0.05);\nmargin-bottom: 20px;\n}\n\n.remotes-grid {\ndisplay: grid;\ngrid-template-columns: repeat(auto-fit, minmax(220px, 1fr));\ngap: 15px;\nmargin-top: 15px;\n}\n\n.remote-link {\ndisplay: block;\npadding: 15px;\ntext-decoration: none;\nbackground: var(--primary);\ncolor: white;\nborder-radius: 10px;\ntext-align: center;\nfont-weight: 500;\ntransition: background 0.2s ease, transform 0.1s ease;\n}\n\n.remote-link:hover {\nbackground: var(--primary-hover);\ntransform: translateY(-2px);\n}\n\n#received_ir_command {\nfont-family: monospace;\nbackground: #111827;\ncolor: #10b981;\npadding: 15px;\nborder-radius: 8px;\nmargin-top: 10px;\noverflow-x: auto;\nwhite-space: pre-wrap;\nword-break: break-word;\n}\n\n.status-label {\nfont-weight: 600;\nmargin-bottom: 5px;\n}\n\n@media (max-width: 480px) {\n.container {\npadding: 15px;\n}\n\n.card {\npadding: 15px;\n}\n}\n</style>\n</head>\n\n<body>\n\n<div class=\"container\">\n\n<h1>CouchPotatoRemotes</h1>\n\n<div class=\"card\">\n<h2>Available Remotes</h2>\n<div class=\"remotes-grid\">\n<a class=\"remote-link\" href=\"/remote-xanlite-rgb\">\nXanlite RGB Remote\n</a>\n\n<!-- Future remotes:\n<a class=\"remote-link\" href=\"/remote-tv\">\nTV Remote\n</a>\n-->\n</div>\n</div>\n\n<div class=\"card\">\n<h2>Last IR Command</h2>\n<div id=\"received_ir_command\">Waiting...</div>\n</div>\n</div>\n\n<script>\nconst irDisplay = document.getElementById(\"received_ir_command\");\nlet lastValue = \"\";\n\nfunction fetchIR() {\nfetch(\"/recvir\")\n.then(response => response.text())\n.then(data => {\nif (data !== lastValue) {\nirDisplay.textContent = data;\nlastValue = data;\n}\n})\n.catch(err => {\nirDisplay.textContent = \"Error fetching IR data\";\n});\n}\nsetInterval(fetchIR, 250);\n</script>\n\n</body>\n</html>";
#endif
